from dataclasses import dataclass
import numpy as np

GPU_MEM_SIZE = 80  # GB

@dataclass
class Model:
    model_name: str
    model_size: int
    req_rate: int
    slo: int
    cur_gpu_id: int


def compute_model_placement(gpu_num: int, models: list[Model]) -> dict[int, list[Model]]:
    """
    Design: Binary Search over KVPR (BS-KVPR) with Vector Bin Packing.

    Algorithmic Paradigm: 
    Instead of greedy construction (Seed 1) or local improvement (Seed 2), 
    this algorithm treats the problem as a feasibility problem. 
    We binary search for the minimum achievable maximum KVPR (target_kvpr).

    For a fixed 'target_kvpr', the constraint for each GPU becomes:
    sum(w_i) / (GPU_MEM_SIZE - sum(s_i)) <= target_kvpr
    where w_i = req_rate/slo and s_i = model_size.

    This can be rewritten as a linear constraint:
    sum(w_i + target_kvpr * s_i) <= target_kvpr * GPU_MEM_SIZE

    This transforms the problem into a "Bin Packing" problem where each item i 
    has a weight: (w_i + target_kvpr * s_i) and bins have capacity: (target_kvpr * GPU_MEM_SIZE).
    Additionally, we must respect the hard constraint: sum(s_i) <= 80.
    """

    def is_feasible(target_kvpr):
        """Checks if a placement exists such that max KVPR <= target_kvpr."""
        # Compute combined weight for each model: w + target_kvpr * s
        combined = []
        for m in models:
            w = m.req_rate / m.slo
            s = m.model_size
            combined.append((w + target_kvpr * s, m))
        # Sort by combined weight descending
        combined.sort(key=lambda x: x[0], reverse=True)

        capacity = target_kvpr * GPU_MEM_SIZE
        # If target_kvpr is 0, then capacity is 0. Then we require all combined weights to be 0.
        if target_kvpr == 0:
            # If any model has w>0, then combined weight>0, so infeasible.
            if any(m.req_rate > 0 for m in models):
                return False, {}
            else:
                # All zeros, any placement works.
                placement = {i: [] for i in range(gpu_num)}
                for m in models:
                    placement[0].append(m)  # arbitrarily place on GPU0
                return True, placement

        bin_loads = [0.0] * gpu_num
        bin_mem = [0] * gpu_num
        placement = {i: [] for i in range(gpu_num)}

        for c, model in combined:
            # Find the bin with the smallest remaining capacity that can fit this model
            # while also respecting memory constraint
            best_idx = -1
            best_remain = capacity
            for i in range(gpu_num):
                if bin_loads[i] + c <= capacity and bin_mem[i] + model.model_size <= GPU_MEM_SIZE:
                    remain = capacity - (bin_loads[i] + c)
                    if remain < best_remain:
                        best_remain = remain
                        best_idx = i
            if best_idx >= 0:
                bin_loads[best_idx] += c
                bin_mem[best_idx] += model.model_size
                placement[best_idx].append(model)
            else:
                return False, {}
        return True, placement

    # Define search range for KVPR
    # Lower bound: maximum KVPR if each model were placed alone on a GPU (must be at least this)
    low = 0.0
    for m in models:
        if m.model_size < GPU_MEM_SIZE:
            kv = (m.req_rate / m.slo) / (GPU_MEM_SIZE - m.model_size)
            if kv > low:
                low = kv
    # Upper bound: worst‑case KVPR when all models are crammed onto as few GPUs as possible
    # Use a greedy that respects memory and tries to balance load.
    # Sort by decreasing weight/size ratio to pack high pressure first.
    sorted_models = sorted(models, key=lambda m: m.req_rate / max(m.slo, 1) / max(m.model_size, 1), reverse=True)
    gpu_mem = [0] * gpu_num
    gpu_weight = [0.0] * gpu_num
    for m in sorted_models:
        best_gpu = -1
        best_kv_after = float('inf')
        for g_id in range(gpu_num):
            if gpu_mem[g_id] + m.model_size <= GPU_MEM_SIZE:
                new_w = gpu_weight[g_id] + m.req_rate / m.slo
                new_s = gpu_mem[g_id] + m.model_size
                if GPU_MEM_SIZE - new_s > 0:
                    kv = new_w / (GPU_MEM_SIZE - new_s)
                else:
                    kv = float('inf')
                if kv < best_kv_after:
                    best_kv_after = kv
                    best_gpu = g_id
        if best_gpu == -1:
            # Fallback: first‑fit by memory
            for g_id in range(gpu_num):
                if gpu_mem[g_id] + m.model_size <= GPU_MEM_SIZE:
                    best_gpu = g_id
                    break
        gpu_mem[best_gpu] += m.model_size
        gpu_weight[best_gpu] += m.req_rate / m.slo
    # Compute KVPR for each GPU
    high_vals = []
    for g_id in range(gpu_num):
        if GPU_MEM_SIZE - gpu_mem[g_id] > 0:
            high_vals.append(gpu_weight[g_id] / (GPU_MEM_SIZE - gpu_mem[g_id]))
    high = max(high_vals) if high_vals else low + 10.0
    # Ensure high > low
    if high <= low:
        high = low + 1.0
    # Add a small epsilon to avoid floating-point equality issues
    high += 1e-9

    best_overall_placement = None
    best_kvpr = float('inf')

    # Binary search for the optimal KVPR threshold
    for _ in range(80):  # Increased iterations for finer granularity
        mid = (low + high) / 2
        feasible, placement = is_feasible(mid)
        if feasible:
            # Compute actual max KVPR for this placement (may be lower than mid)
            # and store the placement if it improves the best found so far.
            # Compute actual KVPRs:
            actual_kvprs = []
            for g_id in range(gpu_num):
                total_w = sum(m.req_rate / m.slo for m in placement[g_id])
                total_s = sum(m.model_size for m in placement[g_id])
                if GPU_MEM_SIZE - total_s > 0:
                    actual_kvprs.append(total_w / (GPU_MEM_SIZE - total_s))
            if actual_kvprs:
                actual_max = max(actual_kvprs)
                if actual_max < best_kvpr:
                    best_kvpr = actual_max
                    best_overall_placement = placement
            high = mid
        else:
            low = mid
        # Early stop if high - low is very small
        if high - low < 1e-12:
            break

    # If binary search failed to find a valid placement, use a refined greedy fallback
    if best_overall_placement is None:
        # Try a multi‑pass greedy that minimizes KVPR increase
        best_overall_placement = {i: [] for i in range(gpu_num)}
        # Sort by decreasing weight/size ratio (density)
        sorted_models = sorted(models, key=lambda m: (m.req_rate / m.slo) / max(m.model_size, 1), reverse=True)
        gpu_mem = [0] * gpu_num
        gpu_weight = [0.0] * gpu_num
        for m in sorted_models:
            best_gpu = -1
            best_kv_after = float('inf')
            # Try each GPU that has enough memory, pick the one with smallest KV after placement
            for g_id in range(gpu_num):
                if gpu_mem[g_id] + m.model_size <= GPU_MEM_SIZE:
                    new_w = gpu_weight[g_id] + m.req_rate / m.slo
                    new_s = gpu_mem[g_id] + m.model_size
                    if GPU_MEM_SIZE - new_s > 0:
                        kv_after = new_w / (GPU_MEM_SIZE - new_s)
                    else:
                        kv_after = float('inf')
                    if kv_after < best_kv_after:
                        best_kv_after = kv_after
                        best_gpu = g_id
            if best_gpu != -1:
                best_overall_placement[best_gpu].append(m)
                gpu_mem[best_gpu] += m.model_size
                gpu_weight[best_gpu] += m.req_rate / m.slo
            else:
                # Fallback: first‑fit by memory
                for g_id in range(gpu_num):
                    if gpu_mem[g_id] + m.model_size <= GPU_MEM_SIZE:
                        best_overall_placement[g_id].append(m)
                        gpu_mem[g_id] += m.model_size
                        break

    # Ensure all models are placed (should always be true)
    placed_models = set()
    for gpu_list in best_overall_placement.values():
        for m in gpu_list:
            placed_models.add(m.model_name)
    if len(placed_models) != len(models):
        # fallback: round‑robin placement
        best_overall_placement = {i: [] for i in range(gpu_num)}
        for idx, m in enumerate(models):
            gpu_id = idx % gpu_num
            best_overall_placement[gpu_id].append(m)

    return best_overall_placement

from dataclasses import dataclass
import numpy as np
import collections

GPU_MEM_SIZE = 80  # GB

@dataclass
class Model:
    model_name: str
    model_size: int   # GB
    req_rate: int     # requests per second
    slo: int          # service level objective (latency target)
    cur_gpu_id: int   # current GPU assignment (can be ignored)

def compute_model_placement(gpu_num: int, models: list[Model]) -> dict[int, list[Model]]:
    '''
    Hybrid approach combining binary search feasibility (v2) with local refinement (v1).
    Steps:
    1. Use binary search to find a good KVPR target and a feasible placement.
    2. Perform iterative refinement on that placement to further reduce max KVPR.
    '''
    # Precompute weights
    weights = []
    for m in models:
        weights.append({
            'obj_w': m.req_rate / m.slo,
            'size': m.model_size,
            'model': m
        })

    def is_feasible(target_kvpr):
        """Checks if a placement exists such that max KVPR <= target_kvpr."""
        # Sort by transformed weight (descending) to place hard items first
        sorted_weights = sorted(
            weights, 
            key=lambda x: (x['obj_w'] + target_kvpr * x['size']), 
            reverse=True
        )

        gpu_load_w = [0.0] * gpu_num
        gpu_load_s = [0.0] * gpu_num
        temp_placement = {i: [] for i in range(gpu_num)}

        for item in sorted_weights:
            best_gpu = -1
            best_remaining = float('inf')

            for g_id in range(gpu_num):
                if gpu_load_s[g_id] + item['size'] > GPU_MEM_SIZE:
                    continue
                new_w = gpu_load_w[g_id] + item['obj_w']
                new_s = gpu_load_s[g_id] + item['size']
                transformed_load = new_w + target_kvpr * new_s
                if transformed_load <= target_kvpr * GPU_MEM_SIZE:
                    remaining = target_kvpr * GPU_MEM_SIZE - transformed_load
                    if remaining < best_remaining:
                        best_remaining = remaining
                        best_gpu = g_id

            if best_gpu == -1:
                return False, {}

            gpu_load_w[best_gpu] += item['obj_w']
            gpu_load_s[best_gpu] += item['size']
            temp_placement[best_gpu].append(item['model'])

        return True, temp_placement

    # Determine search bounds
    low = max(w['obj_w'] / (GPU_MEM_SIZE - w['size']) for w in weights)
    total_weight = sum(w['obj_w'] for w in weights)
    total_size = sum(w['size'] for w in weights)
    if total_size < GPU_MEM_SIZE:
        high = total_weight / (GPU_MEM_SIZE - total_size)
    else:
        high = 1e9
    high = max(high, max(w['obj_w'] / (GPU_MEM_SIZE - w['size']) for w in weights), 20.0)

    best_placement = None
    # Binary search for best target KVPR
    for _ in range(60):
        mid = (low + high) / 2
        feasible, placement = is_feasible(mid)
        if feasible:
            best_placement = placement
            high = mid
        else:
            low = mid

    # Fallback to greedy if binary search failed
    if best_placement is None:
        best_placement = {i: [] for i in range(gpu_num)}
        sorted_models = sorted(models, key=lambda m: (m.req_rate / m.slo) / m.model_size if m.model_size > 0 else 0, reverse=True)
        gpu_mem = [0] * gpu_num
        for m in sorted_models:
            best_gpu = -1
            best_kvpr = float('inf')
            for g_id in range(gpu_num):
                if gpu_mem[g_id] + m.model_size <= GPU_MEM_SIZE:
                    total_weight = sum(mm.req_rate / mm.slo for mm in best_placement[g_id]) + m.req_rate / m.slo
                    used_mem = gpu_mem[g_id] + m.model_size
                    remaining = GPU_MEM_SIZE - used_mem
                    if remaining > 0:
                        candidate = total_weight / remaining
                        if candidate < best_kvpr:
                            best_kvpr = candidate
                            best_gpu = g_id
            if best_gpu != -1:
                best_placement[best_gpu].append(m)
                gpu_mem[best_gpu] += m.model_size
            else:
                for g_id in range(gpu_num):
                    if gpu_mem[g_id] + m.model_size <= GPU_MEM_SIZE:
                        best_placement[g_id].append(m)
                        gpu_mem[g_id] += m.model_size
                        break

    # ---- Local Refinement (like v1) ----
    def get_kvpr(gpu_id, p):
        m_sum = sum(m.model_size for m in p[gpu_id])
        w_sum = sum(m.req_rate / m.slo for m in p[gpu_id])
        if m_sum >= GPU_MEM_SIZE: 
            return float('inf')
        return w_sum / (GPU_MEM_SIZE - m_sum)

    improved = True
    max_passes = 100
    for _ in range(max_passes):
        improved = False
        gpu_kvprs = [get_kvpr(i, best_placement) for i in range(gpu_num)]
        max_kvpr_val = max(gpu_kvprs)
        bottleneck = np.argmax(gpu_kvprs)

        # Try moving a model out of bottleneck
        for idx, model in enumerate(best_placement[bottleneck]):
            w_m = model.req_rate / model.slo
            s_m = model.model_size
            candidate_gpus = sorted(range(gpu_num), key=lambda g: get_kvpr(g, best_placement))
            for target in candidate_gpus:
                if target == bottleneck:
                    continue
                if sum(m.model_size for m in best_placement[target]) + s_m >= GPU_MEM_SIZE:
                    continue
                src_w = sum(m.req_rate / m.slo for m in best_placement[bottleneck]) - w_m
                src_s = sum(m.model_size for m in best_placement[bottleneck]) - s_m
                tgt_w = sum(m.req_rate / m.slo for m in best_placement[target]) + w_m
                tgt_s = sum(m.model_size for m in best_placement[target]) + s_m
                new_src_kvpr = src_w / (GPU_MEM_SIZE - src_s) if src_s < GPU_MEM_SIZE else float('inf')
                new_tgt_kvpr = tgt_w / (GPU_MEM_SIZE - tgt_s) if tgt_s < GPU_MEM_SIZE else float('inf')
                new_max = max(new_src_kvpr, new_tgt_kvpr)
                if new_max < max_kvpr_val - 1e-12:
                    best_placement[bottleneck].pop(idx)
                    best_placement[target].append(model)
                    improved = True
                    break
            if improved:
                break
        if improved:
            continue

        # Try swapping models
        sorted_gpus = sorted(range(gpu_num), key=lambda g: get_kvpr(g, best_placement))
        for other in sorted_gpus:
            if other == bottleneck:
                continue
            for i, m1 in enumerate(best_placement[bottleneck]):
                for j, m2 in enumerate(best_placement[other]):
                    src_mem = sum(m.model_size for m in best_placement[bottleneck]) - m1.model_size + m2.model_size
                    oth_mem = sum(m.model_size for m in best_placement[other]) - m2.model_size + m1.model_size
                    if src_mem >= GPU_MEM_SIZE or oth_mem >= GPU_MEM_SIZE:
                        continue
                    src_w = sum(m.req_rate / m.slo for m in best_placement[bottleneck]) - (m1.req_rate / m1.slo) + (m2.req_rate / m2.slo)
                    oth_w = sum(m.req_rate / m.slo for m in best_placement[other]) - (m2.req_rate / m2.slo) + (m1.req_rate / m1.slo)
                    new_src_kvpr = src_w / (GPU_MEM_SIZE - src_mem)
                    new_oth_kvpr = oth_w / (GPU_MEM_SIZE - oth_mem)
                    if max(new_src_kvpr, new_oth_kvpr) < max_kvpr_val - 1e-12:
                        best_placement[bottleneck][i], best_placement[other][j] = m2, m1
                        improved = True
                        break
                if improved:
                    break
            if improved:
                break
        if not improved:
            break

    return best_placement

from dataclasses import dataclass
import numpy as np
import collections

GPU_MEM_SIZE = 80  # GB

@dataclass
class Model:
    model_name: str
    model_size: int   # GB
    req_rate: int     # requests per second
    slo: int          # service level objective (latency target)
    cur_gpu_id: int   # current GPU assignment (can be ignored)

def compute_model_placement(gpu_num: int, models: list[Model]) -> dict[int, list[Model]]:
    '''
    Algorithm: Binary search on target KVPR with linear cost bin packing and local refinement.
    '''
    import random
    import math

    # Precompute weight for each model
    for m in models:
        m.weight = m.req_rate / m.slo

    # Helper function to compute KVPR of a list of models
    def kvpr_of_models(model_list):
        if not model_list:
            return 0.0
        total_weight = sum(m.weight for m in model_list)
        total_size = sum(m.model_size for m in model_list)
        if total_size >= GPU_MEM_SIZE:
            return float('inf')
        return total_weight / (GPU_MEM_SIZE - total_size)

    # Binary search feasibility test
    def can_pack(target_kvpr):
        # Capacity per GPU: weight + target_kvpr * size < target_kvpr * 80
        cap = target_kvpr * GPU_MEM_SIZE - 1e-9
        items = []
        for m in models:
            cost = m.weight + target_kvpr * m.model_size
            items.append((cost, m))
        # Sort by cost descending
        items.sort(key=lambda x: x[0], reverse=True)
        bins = [0.0] * gpu_num
        placement = {i: [] for i in range(gpu_num)}
        for cost, model in items:
            # Find the bin with smallest current cost that can fit this item
            best_idx = -1
            min_bin_val = float('inf')
            for i in range(gpu_num):
                if bins[i] + cost <= cap:
                    if bins[i] < min_bin_val:
                        min_bin_val = bins[i]
                        best_idx = i
            if best_idx == -1:
                return False, {}
            bins[best_idx] += cost
            placement[best_idx].append(model)
        return True, placement

    # Binary search bounds
    total_weight = sum(m.weight for m in models)
    total_size = sum(m.model_size for m in models)
    low = 0.0
    # Upper bound: worst-case KVPR if all models on one GPU (if fits) or single model with highest density
    high = 0.0
    for m in models:
        if m.model_size < GPU_MEM_SIZE:
            kv = m.weight / (GPU_MEM_SIZE - m.model_size)
            if kv > high:
                high = kv
    if total_size < GPU_MEM_SIZE:
        kv_all = total_weight / (GPU_MEM_SIZE - total_size)
        if kv_all > high:
            high = kv_all
    high = max(high, 1e-6)
    # Ensure we have a feasible upper bound (by doubling until feasible)
    for _ in range(20):
        feasible, _ = can_pack(high)
        if feasible:
            break
        high *= 2

    # Binary search
    best_placement = None
    for _ in range(50):
        mid = (low + high) / 2
        feasible, placement = can_pack(mid)
        if feasible:
            best_placement = placement
            high = mid
        else:
            low = mid

    # Fallback if no feasible placement found (should not happen)
    if best_placement is None:
        # Greedy fallback
        best_placement = {i: [] for i in range(gpu_num)}
        gpu_mem = [0] * gpu_num
        gpu_weight = [0.0] * gpu_num
        for m in models:
            best_gpu = -1
            best_kvpr = float('inf')
            for g in range(gpu_num):
                if gpu_mem[g] + m.model_size <= GPU_MEM_SIZE:
                    new_w = gpu_weight[g] + m.weight
                    new_m = gpu_mem[g] + m.model_size
                    kv = new_w / (GPU_MEM_SIZE - new_m)
                    if kv < best_kvpr:
                        best_kvpr = kv
                        best_gpu = g
            if best_gpu >= 0:
                best_placement[best_gpu].append(m)
                gpu_mem[best_gpu] += m.model_size
                gpu_weight[best_gpu] += m.weight
            else:
                # If no GPU can hold the model, force to the one with most free memory
                best_gpu = max(range(gpu_num), key=lambda g: GPU_MEM_SIZE - gpu_mem[g])
                best_placement[best_gpu].append(m)
                gpu_mem[best_gpu] += m.model_size
                gpu_weight[best_gpu] += m.weight

    # Local refinement to reduce max KVPR
    def max_kvpr(placement):
        return max(kvpr_of_models(placement[i]) for i in range(gpu_num))

    current_cost = max_kvpr(best_placement)
    for _ in range(1000):
        kvprs = [kvpr_of_models(best_placement[i]) for i in range(gpu_num)]
        src = max(range(gpu_num), key=lambda i: kvprs[i])
        dst = min(range(gpu_num), key=lambda i: kvprs[i])
        if not best_placement[src]:
            continue
        improved = False
        # Try moving each model from src to dst
        for model in best_placement[src][:]:
            dst_mem = sum(m.model_size for m in best_placement[dst])
            if dst_mem + model.model_size <= GPU_MEM_SIZE:
                # Simulate move
                best_placement[src].remove(model)
                best_placement[dst].append(model)
                new_cost = max_kvpr(best_placement)
                if new_cost < current_cost:
                    current_cost = new_cost
                    improved = True
                    break
                else:
                    # Revert
                    best_placement[dst].remove(model)
                    best_placement[src].append(model)
        if improved:
            continue
        # Try swapping between src and dst
        for model_src in best_placement[src][:]:
            for model_dst in best_placement[dst][:]:
                # Check memory after swap
                src_mem = sum(m.model_size for m in best_placement[src]) - model_src.model_size + model_dst.model_size
                dst_mem = sum(m.model_size for m in best_placement[dst]) - model_dst.model_size + model_src.model_size
                if src_mem > GPU_MEM_SIZE or dst_mem > GPU_MEM_SIZE:
                    continue
                # Perform swap
                best_placement[src].remove(model_src)
                best_placement[dst].remove(model_dst)
                best_placement[src].append(model_dst)
                best_placement[dst].append(model_src)
                new_cost = max_kvpr(best_placement)
                if new_cost < current_cost:
                    current_cost = new_cost
                    improved = True
                    break
                else:
                    # Revert swap
                    best_placement[src].remove(model_dst)
                    best_placement[dst].remove(model_src)
                    best_placement[src].append(model_src)
                    best_placement[dst].append(model_dst)
            if improved:
                break
        if not improved:
            break

    return best_placement
